# create_baseline_repo.ps1\n\nfunction Create-BaselineRepository {\n    param (\n        [string]$RepoName = $(Read-Host \"Enter the name for the new repository (e.g., MyNewProject)\")\n    )\n\n    if ([string]::IsNullOrWhiteSpace($RepoName)) {\n        Write-Error \"Repository name cannot be empty.\" -ErrorAction Stop\n        return\n    }\n\n    $NewRepoPath = Join-Path (Get-Location).Path $RepoName\n    \n    Write-Host \"Creating new repository at: $NewRepoPath\"\n\n    try {\n        # Create the new repository directory\n        New-Item -ItemType Directory -Path $NewRepoPath -Force | Out-Null\n    } catch {\n        Write-Error \"Failed to create new repository directory: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    # Navigate into the new directory\n    Set-Location $NewRepoPath\n\n    # Ensure .env.local and cfg directory exist\n    $EnvFilePath = Join-Path $NewRepoPath \".env.local\"\n    $CfgPath = Join-Path $NewRepoPath \"cfg\"\n    try {\n        New-Item -ItemType Directory -Path $CfgPath -Force | Out-Null\n        New-Item -ItemType File -Path $EnvFilePath -Force | Out-Null\n        # Add .env.local to .gitignore if it doesn't exist\n        if (-not (Get-Content (Join-Path $NewRepoPath \".gitignore\") -Raw -ErrorAction SilentlyContinue) -match \".env.local\") {\n            Add-Content -Path (Join-Path $NewRepoPath \".gitignore\") -Value \".env.local\"\n        }\n    } catch {\n        Write-Error \"Failed to create .env.local or cfg directory: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    # Read existing .env.local for values\n    $EnvVars = @{}\n    try {\n        $EnvContent = Get-Content $EnvFilePath -Raw -ErrorAction SilentlyContinue\n        if ($EnvContent) {\n            $EnvContent.Split(\"`n\") | ForEach-Object {\n                if ($_ -match \"^\\s*([^=]+?)\\s*=\\s*(.*)\\s*$\") {\n                    $EnvVars[$matches[1]] = $matches[2]\n                }\n            }\n        }\n    } catch {\n        Write-Warning \"Could not read .env.local: $($_.Exception.Message)\"\n    }\n\n    # Configure Git User Name\n    $GitUserName = \"AgentDraven\"\n    try {\n        git config user.name \"$GitUserName\" | Out-Null\n        if ($LASTEXITCODE -ne 0) { throw \"Git config user.name failed with exit code $LASTEXITCODE.\" }\n        Write-Host \"Configured Git user.name as \'$GitUserName\'.\"\n    } catch {\n        Write-Error \"Failed to configure Git user.name: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    # Configure Git User Email\n    $GitUserEmail = $EnvVars[\"GIT_USER_EMAIL\"]\n    if ([string]::IsNullOrWhiteSpace($GitUserEmail)) {\n        $GitUserEmail = Read-Host \"Enter your Git email address (will be saved in .env.local if you wish)\"\n        Add-Content -Path $EnvFilePath -Value \"GIT_USER_EMAIL=$GitUserEmail\"\n        Write-Host \"Git email saved to .env.local.\"\n    }\n    try {\n        git config user.email \"$GitUserEmail\" | Out-Null\n        if ($LASTEXITCODE -ne 0) { throw \"Git config user.email failed with exit code $LASTEXITCODE.\" }\n        Write-Host \"Configured Git user.email as \'$GitUserEmail\'.\"\n    } catch {\n        Write-Error \"Failed to configure Git user.email: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    # GitHub Personal Access Token (PAT)\n    $GitHubToken = $EnvVars[\"GITHUB_TOKEN\"]\n    if ([string]::IsNullOrWhiteSpace($GitHubToken)) {\n        Write-Host \"`nNOTICE: GitHub Personal Access Token (PAT) is required for automated push.\"\n        Write-Host \"Please generate one at https://github.com/settings/tokens with 'repo' scope.\"\n        Write-Host \"Add it manually to the .env.local file in the new repository as GITHUB_TOKEN=YOUR_PAT.\"\n        Write-Host \"Alternatively, you can enter it now, but it will only be used for this session and NOT saved in plaintext.\"\n        $SecureToken = Read-Host -AsSecureString \"Enter your GitHub PAT (not saved to .env.local in plaintext)\"\n        $GitHubToken = [System.Runtime.InteropServices.Marshal]::PtrToStringAuto([System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($SecureToken))\n        \n        # Add a placeholder to .env.local if not already there\n        if (-not $EnvContent -match \"^\\s*GITHUB_TOKEN=\") {\n            Add-Content -Path $EnvFilePath -Value \"GITHUB_TOKEN=YOUR_GITHUB_PERSONAL_ACCESS_TOKEN_HERE\"\n            Write-Host \"A placeholder for GITHUB_TOKEN has been added to .env.local. Please update it manually.\"\n        }\n    }\n    \n    # Initialize Git Repository\n    try {\n        git init | Out-Null\n        if ($LASTEXITCODE -ne 0) { throw \"Git init failed with exit code $LASTEXITCODE.\" }\n        Write-Host \"Initialized empty Git repository in \\\'$NewRepoPath\\\'.\"\n    } catch {\n        Write-Error \"Failed to initialize Git repository: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    # Create docs directory and copy BOOTSTRAPPING.md\n    $DocsPath = Join-Path $NewRepoPath \"docs\"\n    try {\n        New-Item -ItemType Directory -Path $DocsPath -Force | Out-Null\n        Copy-Item -Path \"C:\\\\Users\\\\balap\\\\AgentDraven\\\\BAIC\\\\docs\\\\BOOTSTRAPPING.md\" -Destination $DocsPath -Force | Out-Null\n        if ($LASTEXITCODE -ne 0) { throw \"Copying BOOTSTRAPPING.md failed with exit code $LASTEXITCODE.\" }\n        Write-Host \"Copied BOOTSTRAPPING.md to \\\'$DocsPath\\\'.\"\n    } catch {\n        Write-Error \"Failed to copy BOOTSTRAPPING.md: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    # Add remote repository\n    $RemoteUrl = \"https://github.com/${GitUserName}/${RepoName}.git\"\n    try {\n        git remote add origin $RemoteUrl | Out-Null\n        if ($LASTEXITCODE -ne 0) { throw \"Git remote add origin failed with exit code $LASTEXITCODE.\" }\n        Write-Host \"Added remote repository: $RemoteUrl\"\n    } catch {\n        Write-Error \"Failed to add remote repository: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    # Stage and commit the initial BOOTSTRAPPING.md\n    try {\n        git add . | Out-Null\n        if ($LASTEXITCODE -ne 0) { throw \"Git add failed with exit code $LASTEXITCODE.\" }\n        git commit -m \"feat: Initial repository setup with bootstrapping instructions\" | Out-Null\n        if ($LASTEXITCODE -ne 0) { throw \"Git commit failed with exit code $LASTEXITCODE.\" }\n        Write-Host \"Initial commit created.\"\n    } catch {\n        Write-Error \"Failed to create initial commit: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    # Push to remote\n    try {\n        git branch -M main | Out-Null\n        if ($LASTEXITCODE -ne 0) { throw \"Git branch -M main failed with exit code $LASTEXITCODE.\" }\n        \n        # Attempt push with PAT if available, otherwise rely on credential manager or manual prompt\n        if (-not [string]::IsNullOrWhiteSpace($GitHubToken)) {\n            # This pushes using HTTPS and the PAT. Git will try to use the credential manager first.\n            # If it fails, it might prompt, or the PAT in the URL *could* work as fallback (less secure for embedded token).\n            # A better approach for enterprise is `git config --local credential.helper store` or similar, but outside this script\'s scope.\n            Write-Host \"Attempting to push using the provided GitHub PAT...\"\n            $pushResult = git push -u origin main 2>&1\n            if ($LASTEXITCODE -ne 0) { \n                Write-Error \"Git push failed: `$($pushResult -join \`n`)\". This might be due to incorrect PAT, insufficient permissions, or repository not existing on GitHub. Please check the error message above.\" -ErrorAction Stop\n                return\n            }\n        } else {\n            Write-Host \"No GitHub PAT provided. Attempting to push. You may be prompted for credentials.\"\n            $pushResult = git push -u origin main 2>&1\n            if ($LASTEXITCODE -ne 0) { \n                Write-Error \"Git push failed: `$($pushResult -join \`n`)\". Please check the error message above.\" -ErrorAction Stop\n                return\n            }\n        }\n\n        Write-Host \"Pushed initial commit to remote.\"\n    } catch {\n        Write-Error \"Failed to push to remote: $($_.Exception.Message)\" -ErrorAction Stop\n        return\n    }\n\n    Write-Host \"`nRepository \\\'$RepoName\\\' created and bootstrapped successfully.\"\n    Write-Host \"Your Git email has been saved in \\\'.env.local\\\' in the new repository. Please ensure GITHUB_TOKEN is manually added there.\"\n\n    # Return to the original location\n    Set-Location C:\\\\Users\\\\balap\\\\AgentDraven\\\\BAIC\n}\n\n# Invoke the function\nCreate-BaselineRepository